function baseRate(item: Item): number {
  if (item.kind === "cursed") return CURSE_RATE;
  if (item.kind === "magical") return MAGICAL_SURCHARGE_RATE;
  return 0;
}

function highEnchantmentBonus(item: Item): number {
  const applies =
    item.kind === "cursed"
      ? Boolean(item.highEnchantmentApplies) && isHighEnchantment(item)
      : item.kind === "magical" && isHighEnchantment(item);
  return applies ? HIGH_ENCHANTMENT_RATE : 0;
}

function itemSurchargeRate(item: Item): number {
  return baseRate(item) + highEnchantmentBonus(item);
}

